mapper.update:
update ai_personality
set name          = #{roleName},
    system_prompt = #{content}
where id = #{id}

mapper.delete:
update ai_personality
set is_active = 0
where user_id = #{userId}

mapper.update:
update ai_personality
set is_active = 1
where id = #{id}
  and user_id = #{userId}

mapper.select:
select avatar
from ai_personality
where id = #{id}
  and user_id = #{userId}
